import java.io.BufferedReader;
import java.io.File;
import java.io.FileReader;
import java.io.IOException;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String userInput = "../secret_files/important.txt";
        String baseDirectory = "/home/user/public_files/";
        String sanitizedInput = userInput.replaceAll("\\.\\.", "");

        String filePath = new File(baseDirectory, sanitizedInput).getAbsolutePath();

        if (filePath.startsWith(baseDirectory)) {
            try {
                File file = new File(filePath);
                BufferedReader reader = new BufferedReader(new FileReader(file));
                String line;
                while ((line = reader.readLine()) != null) {
                    System.out.println(line);
                }
                reader.close();
            } catch (IOException e) {
                System.out.println("Error reading file: " + e.getMessage());
            }
        } else {
            System.out.println("Invalid file path.");
        }
    }
}

